// Compact range-based implementation replacing the auto-generated trie tables.
// Width data derived from Unicode 17.0.0 via binary-search over (lo, hi) ranges.
// Simplification: ligature state-machine (Arabic Lam-Alef, Buginese ya,
// Khmer coeng, emoji ZWJ sequences) is omitted — not relevant for terminal UI.

use core::cmp::Ordering;

