#[inline]
fn in_range(table: &[(u32, u32)], cp: u32) -> bool {
    table
        .binary_search_by(|&(lo, hi)| {
            if cp < lo {
                Ordering::Greater
            } else if cp > hi {
                Ordering::Less
            } else {
                Ordering::Equal
            }
        })
        .is_ok()
}

/// Returns raw width: -1 for control, 0 for zero-width, 1 for normal, 2 for wide.
#[inline]
fn char_width_raw(c: char) -> i8 {
    // Bengali spacing marks: glibc wcwidth() returns 1 but Unicode Grapheme_Extend
    // marks them as zero-width. Override to match glibc and avoid cursor desync.
    if matches!(
        c,
        '\u{09BE}'
            | '\u{09BF}'
            | '\u{09C0}'
            | '\u{09C7}'
            | '\u{09C8}'
            | '\u{09CB}'
            | '\u{09CC}'
            | '\u{09D7}'
    ) {
        return 1;
    }
    let cp = c as u32;
    if cp < 0x20 || (0x7F..0xA0).contains(&cp) {
        return -1; // control character
    }
    if cp < 0xA0 {
        return 1; // printable ASCII (0x20..=0x7E)
    }
    if in_range(ZERO_WIDTH, cp) {
        return 0;
    }
    if in_range(WIDE, cp) {
        return 2;
    }
    1
}

/// Returns raw width for CJK context: -1 for control, 0 for zero-width, 1/2 for wide.
#[cfg(feature = "cjk")]
#[inline]
fn char_width_raw_cjk(c: char) -> i8 {
    // Same Bengali override as non-CJK.
    if matches!(
        c,
        '\u{09BE}'
            | '\u{09BF}'
            | '\u{09C0}'
            | '\u{09C7}'
            | '\u{09C8}'
            | '\u{09CB}'
            | '\u{09CC}'
            | '\u{09D7}'
    ) {
        return 1;
    }
    let cp = c as u32;
    if cp < 0x20 || (0x7F..0xA0).contains(&cp) {
        return -1;
    }
    if cp < 0xA0 {
        return 1;
    }
    if in_range(ZERO_WIDTH, cp) {
        return 0;
    }
    if in_range(WIDE_CJK, cp) {
        return 2;
    }
    1
}

/// Returns the [UAX #11](https://www.unicode.org/reports/tr11/) based width of `c`, or
/// `None` if `c` is a control character. Ambiguous width characters treated as narrow.
#[inline]
pub fn single_char_width(c: char) -> Option<usize> {
    match char_width_raw(c) {
        -1 => None,
        w => Some(w as usize),
    }
}

/// Returns the [UAX #11](https://www.unicode.org/reports/tr11/) based width of `c`, or
/// `None` if `c` is a control character. Ambiguous width characters treated as wide (CJK).
#[cfg(feature = "cjk")]
#[inline]
pub fn single_char_width_cjk(c: char) -> Option<usize> {
    match char_width_raw_cjk(c) {
        -1 => None,
        w => Some(w as usize),
    }
}

/// Returns the [UAX #11](https://www.unicode.org/reports/tr11/) based width of `s`.
/// Ambiguous width characters treated as narrow.
#[inline]
pub fn str_width(s: &str) -> usize {
    s.chars().map(|c| char_width_raw(c).max(0) as usize).sum()
}

/// Returns the [UAX #11](https://www.unicode.org/reports/tr11/) based width of `s`.
/// Ambiguous width characters treated as wide (CJK context).
#[cfg(feature = "cjk")]
#[inline]
pub fn str_width_cjk(s: &str) -> usize {
    s.chars()
        .map(|c| char_width_raw_cjk(c).max(0) as usize)
        .sum()
}
